    },
    {
      "name": "grey_hair",
      "zh": "灰发",
      "source": "danbooru",
      "reason": "Danbooru 中银发常归类于或关联灰发标签"
    },
    {
      "name": "white_hair",
      "zh": "白发",
      "source": "danbooru",
      "reason": "银发在部分语境下与白发标签重叠或作为变体"
    },
    {
      "name": "light_blue_eyes",
      "zh": "浅蓝眼",
      "source": "llm_translated",
      "reason": "基于 blue_eyes 生成的更精确颜色变体"
    },
    {
      "name": "dark_blue_eyes",
      "zh": "深蓝眼",
      "source": "llm_translated",
      "reason": "基于 blue_eyes 生成的更精确颜色变体"
    },
    {
      "name": "silvery_white_hair",
      "zh": "银白发",
      "source": "llm_translated",
      "reason": "组合词规则生成的更具体发色描述"
    },
    {
      "name": "platinum_hair",
      "zh": "白金发",
      "source": "danbooru",
      "reason": "银发的常见同义或近义标签"
    },
    {
      "name": "grey_eyes",
      "zh": "灰眼",
      "source": "danbooru",
      "reason": "有时蓝眼与灰眼在视觉上接近，作为相关补充"
    },
    {
      "name": "multicolored_hair",
      "zh": "多彩发",
      "source": "danbooru",
      "reason": "若银发带有其他色调时的潜在关联标签（保守包含）"
    },
    {
      "name": "heterochromia",
      "zh": "异色瞳",
      "source": "danbooru",
      "reason": "虽未明确提及，但作为眼睛颜色特征的常见扩展查询"
    },
    {
      "name": "blue_and_silver",
      "zh": "蓝与银",
      "source": "llm_translated",
      "reason": "应用组合词规则 {color}_and_{color} 描述整体配色"
    },
    {
      "name": "cool_color_scheme",
      "zh": "冷色调配色",
      "source": "llm_translated",
      "reason": "银发蓝眼构成的典型冷色调特征描述"
    },
    {
      "name": "pale_skin",
      "zh": "苍白皮肤",
      "source": "danbooru",
      "reason": "银发蓝眼角色常见的伴随特征"
    },
    {
      "name": "long_hair",
      "zh": "长发",
      "source": "danbooru",
      "reason": "银发角色中常见的发型长度（高频关联）"
    },
    {
      "name": "short_hair",
      "zh": "短发",
      "source": "danbooru",
      "reason": "银发角色中常见的另一种发型长度（高频关联）"
    },
    {
      "name": "twintails",
      "zh": "双马尾",
      "source": "danbooru",
      "reason": "银发蓝眼角色中流行的发型样式"
    },
    {
      "name": "ponytail",
      "zh": "马尾",
      "source": "danbooru",
      "reason": "银发蓝眼角色中流行的发型样式"
    },
    {
      "name": "bangs",
      "zh": "刘海",
      "source": "danbooru",
      "reason": "配合发色的常见面部毛发特征"
    },
    {
      "name": "blunt_bangs",
      "zh": "齐刘海",
      "source": "danbooru",
      "reason": "具体的刘海样式，常用于此类角色"
    }
  ],
  "explanation": "根据用户描述'银发蓝眼'，核心提取了 silver_hair 和 blue_eyes。由于 Danbooru 标签系统的特性，增加了 grey_hair, white_hair, platinum_hair 等同义或近义发色标签以提高检索覆盖率。同时利用组合词规则生成了 blue_and_silver 等描述配色的标签。考虑到此类外貌特征的角色常见搭配，补充了相关的发型（long_hair, twintails 等）和肤色（pale_skin）标签，但严格排除了质量、背景及无关姿势标签。"
}
